/**
 * CesiumJS Map MCP Server
 *
 * Provides tools for:
 * - geocode: Search for places using OpenStreetMap Nominatim
 * - show-map: Display an interactive 3D globe at a given location
 */
import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import type {
  CallToolResult,
  ReadResourceResult,
} from "@modelcontextprotocol/sdk/types.js";
import fs from "node:fs/promises";
import path from "node:path";
import { z } from "zod";
import {
  registerAppTool,
  registerAppResource,
  RESOURCE_MIME_TYPE,
  RESOURCE_URI_META_KEY,
} from "@modelcontextprotocol/ext-apps/server";
import { randomUUID } from "crypto";

// Server-side logger — always use stderr so stdio mode isn't corrupted
const log = {
  tool: (name: string, input: Record<string, unknown>) =>
    console.error(`[TOOL] ${name} called`, Object.keys(input).length ? JSON.stringify(input) : ""),
  done: (name: string, summary?: string) =>
    console.error(`[TOOL] ${name} done${summary ? ` — ${summary}` : ""}`),
  error: (name: string, err: unknown) =>
    console.error(`[ERROR] ${name} failed:`, err instanceof Error ? err.stack ?? err.message : err),
  notify: (method: string) =>
    console.error(`[NOTIFY] sent ${method}`),
  tick: (i: number, total: number) =>
    console.error(`[CLOCK] tick ${i}/${total}`),
};

// Works both from source (server.ts) and compiled (dist/server.js)
const DIST_DIR = import.meta.filename.endsWith(".ts")
  ? path.join(import.meta.dirname, "dist")
  : import.meta.dirname;
const RESOURCE_URI = "ui://cesium-map/mcp-app.html";
const WEATHER_RESOURCE_URI = "ui://weather-dashboard/weather-app.html";
const CLOCK_RESOURCE_URI = "ui://clock-timer/clock-app.html";

// Nominatim API response type
interface NominatimResult {
  place_id: number;
  licence: string;
  osm_type: string;
  osm_id: number;
  lat: string;
  lon: string;
  display_name: string;
  boundingbox: [string, string, string, string]; // [south, north, west, east]
  class: string;
  type: string;
  importance: number;
}

// Rate limiting for Nominatim (1 request per second per their usage policy)
let lastNominatimRequest = 0;
const NOMINATIM_RATE_LIMIT_MS = 1100; // 1.1 seconds to be safe

